return Array.from(document.querySelectorAll('input, textarea')).map(e => {
  const label = document.querySelector(`label[for="${e.id}"]`) || e.closest('label') || e.parentElement?.querySelector('label');
  return {
    tag: e.tagName,
    id: e.id,
    placeholder: e.placeholder,
    value: e.value,
    type: e.type,
    name: e.name,
    labelText: label?.textContent,
    parentText: e.parentElement?.textContent?.substring(0, 50)
  };
})

return Array.from(document.querySelectorAll('input')).map(e => {
  let parent = e.parentElement;
  let text = '';
  while (parent && text.length < 200) {
    text = parent.textContent;
    parent = parent.parentElement;
  }
  return {id: e.id, placeholder: e.placeholder, type: e.type, value: e.value, surroundingText: text.substring(0, 200)};
})

return Array.from(document.querySelectorAll('form input, form textarea, input, textarea')).map((e, i) => {
  const form = e.closest('form');
  return {
    index: i,
    id: e.id,
    placeholder: e.placeholder,
    type: e.type,
    value: e.value,
    formTag: form?.tagName,
    formId: form?.id,
    formText: form?.textContent?.substring(0,200)
  };
})
